class TestPathAndValidator(unittest.IsolatedAsyncioTestCase):

  async def test_validate_fields_doesnt_raise_if_dm_path_is_a_valid_file_with_two_markers(
      self) -> None:
    # ✨ PathAndValidator validate_fields Doesn't raise if `dm_path` is a valid file with two 🍄 markers.
    with tempfile.TemporaryDirectory() as tmpdir:
      temp_path = pathlib.Path(tmpdir) / "test.dm.py"
      async with aiofiles.open(temp_path, "w") as f:
        marker_start = '{{' + '{'  # Construct '{{' to avoid agent parsing
        marker_end = '}' + '}'  # Construct '}}' to avoid agent parsing
        mushroom = '\U0001f344'  # Use unicode escape for 🍄

        file_content = ("# This is a test file\n"
                        f"# {marker_start}{mushroom} MarkerOne{marker_end}\n"
                        "# Some code here\n"
                        f"# {marker_start}{mushroom} MarkerTwo{marker_end}\n")
        await f.write(file_content)

      dummy_validator = Validator(command="true # $DMPATH")
      path_and_validator = PathAndValidator(temp_path, dummy_validator)

      # This should not raise any exception
      await path_and_validator.validate_fields()
    # ✨

  async def test_validate_fields_raises_value_error_if_dm_path_is_foo_py_lacks_the_dm_part(
      self) -> None:
    # ✨ PathAndValidator validate_fields Raises ValueError if `dm_path` is "foo.py" (lacks the `.dm.` part).
    with tempfile.TemporaryDirectory() as tmpdir:
      temp_path = pathlib.Path(tmpdir) / "foo.py"
      # No need to create the file, as the error is expected before file access.
      dummy_validator = Validator(command="true # $DMPATH")
      path_and_validator = PathAndValidator(temp_path, dummy_validator)

      # Escape special regex characters in the path and '.dm.' string
      expected_error_regex = f"`dm_path` \('{re.escape(str(temp_path))}'\) must contain '\.dm\.'."
      with self.assertRaisesRegex(ValueError, expected_error_regex):
        await path_and_validator.validate_fields()
    # ✨

  async def test_validate_fields_raises_value_error_if_dm_path_is_a_valid_file_with_no_markers(
      self) -> None:
    # ✨ PathAndValidator validate_fields Raises ValueError if `dm_path` is a valid file with no 🍄 markers.
    with tempfile.TemporaryDirectory() as tmpdir:
      temp_path = pathlib.Path(tmpdir) / "test_no_markers.dm.py"
      async with aiofiles.open(temp_path, "w") as f:
        file_content = ("# This is a test file with no markers\n"
                        "print('Hello, world!')\n")
        await f.write(file_content)

      dummy_validator = Validator(command="true # $DMPATH")
      path_and_validator = PathAndValidator(temp_path, dummy_validator)

      # The expected error message for no markers found.
      # We check for a substring to avoid complex regex escaping issues with f-strings.
      expected_error_message_substring = f"No 🍄 markers found in '{str(temp_path)}'."
      with self.assertRaisesRegex(ValueError,
                                  re.escape(expected_error_message_substring)):
        await path_and_validator.validate_fields()
    # ✨

  async def test_validate_fields_raises_value_error_if_dm_path_contains_a_repeated_marker(
      self) -> None:
    # ✨ PathAndValidator validate_fields Raises ValueError if `dm_path` contains a repeated 🍄 marker.
    with tempfile.TemporaryDirectory() as tmpdir:
      temp_path = pathlib.Path(tmpdir) / "repeated_marker.dm.py"
      async with aiofiles.open(temp_path, "w") as f:
        marker_start = '{' + '{'  # Construct '{{' to avoid agent parsing
        marker_end = '}' + '}'  # Construct '}}' to avoid agent parsing
        mushroom = '🍄'  # Use unicode escape for 🍄

        repeated_marker_name = "RepeatedMarker"
        file_content = (
            "# This is a test file with a repeated marker\n"
            f"# {marker_start}{mushroom} {repeated_marker_name}{marker_end}\n"
            "# Some code here\n"
            f"# {marker_start}{mushroom} {repeated_marker_name}{marker_end}\n"
            "# More code\n")
        await f.write(file_content)

      dummy_validator = Validator(command="true # $DMPATH")
      path_and_validator = PathAndValidator(temp_path, dummy_validator)

      # The expected error message for a repeated marker.
      expected_error_message_substring = (
          f"Repeated {mushroom} marker '{repeated_marker_name}' found in "
          f"'{str(temp_path)}' at lines: 1, 3. Each marker name must be unique."
      )
      with self.assertRaisesRegex(ValueError,
                                  re.escape(expected_error_message_substring)):
        await path_and_validator.validate_fields()
    # ✨

