  async def test_overwrite_the_read_operation_is_async(self) -> None:
    # ✨ PathAndValidator overwrite The read operation is async
    import unittest.mock as mock

    with tempfile.TemporaryDirectory() as tmpdir:
      dm_file_path = pathlib.Path(tmpdir) / "test_dm_file.dm.py"
      target_file_path = pathlib.Path(tmpdir) / "test_target_file.py"

      # The content that the mocked aiofiles.open (read mode) will return.
      mocked_dm_content = "# Mocked DM Content\nAnother line\n"

      # Determine the expected auto-generated comment for the target file.
      file_extension = FileExtension(
          "py")  # Assuming .py for this test scenario
      auto_gen_comment = comment_string(
          file_extension,
          "DO NOT EDIT. This file is automatically generated by Duende.")

      expected_write_content = f"{auto_gen_comment}\n{mocked_dm_content}"

      dummy_validator = Validator(command="true # $DMPATH")
      path_and_validator = PathAndValidator(dm_file_path, dummy_validator)

      with mock.patch('aiofiles.open') as mock_aiofiles_open:
        # --- Mocks for the read operation ---
        # This is 'f' in 'async with aiofiles.open(..., mode='r') as f:'
        mock_read_file_handle = mock.AsyncMock()
        mock_read_file_handle.read.return_value = mocked_dm_content

        # This IS the async context manager for reading
        mock_read_async_context_manager = mock.AsyncMock()
        mock_read_async_context_manager.__aenter__.return_value = mock_read_file_handle
        mock_read_async_context_manager.__aexit__.return_value = None

        # --- Mocks for the write operation ---
        # This is 'f' in 'async with aiofiles.open(..., mode='w') as f:'
        mock_write_file_handle = mock.AsyncMock()

        # This IS the async context manager for writing
        mock_write_async_context_manager = mock.AsyncMock()
        mock_write_async_context_manager.__aenter__.return_value = mock_write_file_handle
        mock_write_async_context_manager.__aexit__.return_value = None

        def mock_open_side_effect(file_path, mode, **kwargs):
          if mode == 'r':
            return mock_read_async_context_manager
          elif mode == 'w':
            return mock_write_async_context_manager
          else:
            # Fallback for other modes if any, though not expected here
            return mock.AsyncMock()

        mock_aiofiles_open.side_effect = mock_open_side_effect

        # Call the method under test
        await path_and_validator.overwrite(target_file_path)

        # Assertions for the read operation:
        # Verify aiofiles.open was called to read the dm_path
        mock_aiofiles_open.assert_any_call(dm_file_path, mode='r')
        # Verify that the 'read' method on the file handle was awaited once
        mock_read_file_handle.read.assert_awaited_once()

        # Assertions for the write operation:
        # Verify aiofiles.open was called to write to the target_file_path
        mock_aiofiles_open.assert_any_call(target_file_path, mode='w')
        # Verify that the 'write' method on the file handle was awaited once
        mock_write_file_handle.write.assert_awaited_once_with(
            expected_write_content)

        # Ensure that the target file does not exist because the filesystem operations
        # are fully mocked. This confirms the mocks are effectively in place.
        self.assertFalse(target_file_path.exists())
    # ✨

