  async def test_overwrite_the_output_of_a_call_with_a_normal_dm_file_starts_with_the_do_not_edit_code_comment(
      self) -> None:
    # ✨ PathAndValidator overwrite The output of a call with a normal dm file starts with the "DO NOT EDIT code comment
    with tempfile.TemporaryDirectory() as tmpdir:
      dm_file_path = pathlib.Path(tmpdir) / "test.dm.py"
      target_file_path = pathlib.Path(tmpdir) / "test.py"

      dm_content = "print('Hello from DM file!')"
      async with aiofiles.open(dm_file_path, "w") as f:
        await f.write(dm_content)

      dummy_validator = Validator(command="true # $DMPATH")
      path_and_validator = PathAndValidator(dm_file_path, dummy_validator)

      await path_and_validator.overwrite(target_file_path)

      async with aiofiles.open(target_file_path, "r") as f:
        actual_content = await f.read()

      expected_comment = comment_string(
          FileExtension("py"),
          "DO NOT EDIT. This file is automatically generated by Duende.")

      # The actual_content will have the comment plus a newline, then the dm_content.
      # We check if it starts with the expected comment.
      self.assertTrue(actual_content.startswith(f"{expected_comment}\n"))
      self.assertEqual(actual_content.splitlines()[0], expected_comment)
    # ✨

  async def test_overwrite_the_output_of_a_call_with_a_normal_dm_file_contains_a_copy_of_the_dm_file_starting_at_line_2_of_the_output(
      self) -> None:
    # ✨ PathAndValidator overwrite The output of a call with a normal dm file contains a copy (of the dm file), starting at line 2 (of the output)
    with tempfile.TemporaryDirectory() as tmpdir:
      dm_file_path = pathlib.Path(tmpdir) / "test.dm.py"
      target_file_path = pathlib.Path(tmpdir) / "test.py"

      original_dm_content = "line 1 of dm file\nline 2 of dm file\nline 3 of dm file"
      async with aiofiles.open(dm_file_path, "w") as f:
        await f.write(original_dm_content)

      dummy_validator = Validator(command="true # $DMPATH")
      path_and_validator = PathAndValidator(dm_file_path, dummy_validator)

      await path_and_validator.overwrite(target_file_path)

      async with aiofiles.open(target_file_path, "r") as f:
        actual_content = await f.read()

      actual_lines = actual_content.splitlines()

      # The first line is the auto-generated comment, so the dm_content should start from the second line.
      # Join the original_dm_content lines with newline characters to compare correctly.
      self.assertEqual("\n".join(actual_lines[1:]), original_dm_content)
    # ✨


